  if (!allEmpty) filas.push(obj);
});
return [{
  json: { filas, headers, sheetName: ws.name, rowCount: filas.length, sheetNameBuscado: sheetName, fallbackUsed: ws.name !== sheetName },
  binary: item.binary
}];

