const ExcelJS = require('exceljs');
const item = $input.first();
if (!item || !item.binary || !item.binary.data) throw new Error('Sin binary del paso2 banco');
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'banco_paso2'));
const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('paso2 sin worksheets');
const headerRow = ws.getRow(1);
const headers = [];
const colCount = ws.columnCount || 1;
for (let c = 1; c <= colCount; c++) {
  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}
// SELECTIVA: leer hasta encontrar separadora salmon (fila vacia).
// Performance: usar eachRow + retornar 1 SOLO item con array.
const filas = [];
let stopped = false;
ws.eachRow({ includeEmpty: true }, (row, rowNum) => {
  if (rowNum === 1) return;
  if (stopped) return;
  const obj = {};
  let allEmpty = true;
  row.eachCell({ includeEmpty: true }, (cell, colNum) => {
    const h = headers[colNum - 1];
    if (!h) return;
    let v = cell.value;
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 10);
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  });
  if (allEmpty) { stopped = true; return; }
  filas.push(obj);
});
return [{ json: { filas, headers, rowCount: filas.length } }];

// Read banco XLSX retorna 1 item con {filas: [...]}. Tomar filas directo.
const data = $input.first().json;
const movs = data.filas || [];
return [{ json: { banco_name: $('Loop bancos').item.json.name, movs: movs } }];

// Cruzar y conciliar v3 (UNICIDAD BILATERAL + col D banco + _amarillo para marcar paso2)
//
// Reglas:
//  - Solo procesar creditos (col 'debito' = '+'). Descartar debitos ('-').
//  - Conciliar SOLO si el valor es UNICO: 1 vez en bancos Y 1 vez en recargas pendientes.
//  - Cuando es unico: col D (Banco) = banco identificado + col E (Confirmado) = 'Si',
//    y se anota el movimiento de banco (banco+doc+fecha+valor) en _amarillo para marcarlo
//    en amarillo en el paso2 (de donde salio el valor).
//  - Ambiguo: dejar vacio para revision manual.
//  - ID Agencia = 226796 -> col E = 'Ecuabet'.

const yopagoData = $('Aggregate Yopago').first().json.data?.[0] || {filas:[], headers:[]};
const yopagoFilas = yopagoData.filas || [];
const yopagoHeaders = yopagoData.headers || [];
const bancos = $('Aggregate todos los bancos').first().json.data || [];

const ID_INTERNA = '226796';

function nombreBanco(nombreArchivo) {
  const n = String(nombreArchivo || '').toLowerCase();
  if (n.includes('valles') || n.includes('lirio')) return 'Valles de lirio';
  if (n.includes('credil')) return 'Coop Credil';
  if (n.includes('pichincha')) return 'Pichincha';
  return '';
}

// Indexar movimientos de banco por VALOR (solo creditos, ignorar reversos)
const bancoPorValor = {};
let totalMovsLeidos = 0, totalMovsCreditos = 0;
for (const b of bancos) {
  const bancoLabel = nombreBanco(b.banco_name);
  for (const mov of (b.movs || [])) {
    totalMovsLeidos++;
    const debito = String(mov['debito'] || mov.Debito || mov.DEBITO || '').trim();
    const trans = String(mov['transaccion'] || mov.Transaccion || '').toUpperCase();
    if (debito === '-') continue;
    if (trans.includes('REVERSO')) continue;
    const valor = parseFloat(String(mov['valor'] || mov.Valor || '0').replace(/[^0-9.\-]/g, ''));
    if (!valor || valor <= 0) continue;
    const doc = String(mov['documento'] || mov.Documento || '');
    const fecha = String(mov['fecha'] || mov.Fecha || '');
    if (!bancoPorValor[valor]) bancoPorValor[valor] = [];
    bancoPorValor[valor].push({ doc, banco: bancoLabel, fecha, valor });
    totalMovsCreditos++;
  }
}

// Contar recargas PENDIENTES del Yopago por valor (las que aun no tienen Confirmado)
const recargasPendientesPorValor = {};
for (const fila of yopagoFilas) {
  const conf = String(fila.Confirmado || fila.confirmado || '').trim();
  if (conf) continue;
  const id_ag = String(fila['ID Agencia'] || fila.ID || fila.id || '').trim();
  if (!id_ag) continue;
  if (id_ag === ID_INTERNA) continue;
  const valor = parseFloat(String(fila['Valor Recarga'] || fila.Valor || fila.valor || '0').replace(/[^0-9.\-]/g, ''));
  if (!valor || valor <= 0) continue;
  recargasPendientesPorValor[valor] = (recargasPendientesPorValor[valor] || 0) + 1;
}

let conciliadasUnicas = 0, marcadasEcuabet = 0, ambiguas_multiplesBancos = 0, ambiguas_multiplesRecargas = 0, sinMatch = 0;
const _amarillo = []; // movimientos de banco conciliados, a marcar amarillo en paso2

const out = yopagoFilas.map(fila => {
  const conf = String(fila.Confirmado || fila.confirmado || '').trim();
  if (conf) return { ...fila };

  const id_ag = String(fila['ID Agencia'] || fila.ID || fila.id || '').trim();
  const valor = parseFloat(String(fila['Valor Recarga'] || fila.Valor || fila.valor || '0').replace(/[^0-9.\-]/g, ''));
  if (!id_ag || !valor) return { ...fila };

  if (id_ag === ID_INTERNA) { marcadasEcuabet++; return { ...fila, Confirmado: 'Ecuabet' }; }

  const movsConEseValor = bancoPorValor[valor] || [];
  const totalMovs = movsConEseValor.length;
  const totalRecargas = recargasPendientesPorValor[valor] || 0;

  if (totalMovs === 0) { sinMatch++; return { ...fila }; }
  if (totalMovs > 1) { ambiguas_multiplesBancos++; return { ...fila }; }
  if (totalRecargas > 1) { ambiguas_multiplesRecargas++; return { ...fila }; }

  // UNICO: 1 pago banco + 1 recarga yopago con ese valor
  const m = movsConEseValor[0];
  conciliadasUnicas++;
  _amarillo.push({ banco: m.banco, doc: m.doc, fecha: m.fecha, valor: m.valor });
  return { ...fila, Banco: m.banco, Confirmado: 'Si' };
});

const yopagoBinary = $('Read Yopago mes actual').first().binary;
return [{
  json: {
    filas: out,
    headers: yopagoHeaders,
    total: out.length,
    _amarillo,
    _stats: {
      movsLeidos: totalMovsLeidos, movsCreditos: totalMovsCreditos,
      conciliadasUnicas, marcadasEcuabet, ambiguas_multiplesBancos,
      ambiguas_multiplesRecargas, sinMatch,
    }
  },
  binary: yopagoBinary
}];

// === VALIDACION_ROBUSTA_XLSX v2 ===
function _validarXLSX(buf, nombreArchivo) {
  const nombre = nombreArchivo || 'archivo';
  if (!buf || buf.length === 0) throw new Error(`[XLSX_VACIO] El archivo "${nombre}" llego vacio (0 bytes). Re-subir al Drive correctamente.`);
  if (buf.length < 500) throw new Error(`[XLSX_PEQUENO] El archivo "${nombre}" es demasiado pequeno (${buf.length} bytes). Re-subir al Drive.`);
  const b0 = buf[0], b1 = buf[1], b2 = buf[2], b3 = buf[3];
  const esZip = b0 === 0x50 && b1 === 0x4B && (b2 === 0x03 || b2 === 0x05) && (b3 === 0x04 || b3 === 0x06);
  if (!esZip) {
    const hex = [b0,b1,b2,b3].map(b => (b||0).toString(16).padStart(2,'0')).join(' ');
    throw new Error(`[XLSX_FORMATO_INCORRECTO] El archivo "${nombre}" NO es un xlsx. Bytes iniciales: ${hex}. ACCION: re-subir al Drive como .xlsx.`);
  }
  const maxSearch = Math.min(buf.length, 65557);
  let eocd = false;
  for (let i = buf.length - 22; i >= Math.max(0, buf.length - maxSearch); i--) {
    if (buf[i] === 0x50 && buf[i+1] === 0x4B && buf[i+2] === 0x05 && buf[i+3] === 0x06) { eocd = true; break; }
  }
  if (!eocd) throw new Error(`[XLSX_TRUNCADO] El archivo "${nombre}" (${buf.length} bytes) es un zip TRUNCADO o CORRUPTO. ACCION: re-subir el archivo al Drive.`);
}
// === FIN VALIDACION ===

// === FIX DROPDOWNS 2026-06-02 (exceljs PURO, sin jszip que esta bloqueado en el sandbox). ===
function _fixDropdowns(ws, lastRow, srcWs) {
  try {
    const src = (srcWs || ws);
    const srcModel = (src.dataValidations && src.dataValidations.model) || {};
    const cols = {};
    for (const addr of Object.keys(srcModel)) {
      const mm = addr.match(/^([A-Z]+)(\d+)$/);
      if (!mm) continue;
      const col = mm[1], row = parseInt(mm[2], 10), v = srcModel[addr];
      if (!cols[col]) cols[col] = { v: v, minRow: row, maxRow: row };
      else { if (row > cols[col].maxRow) cols[col].maxRow = row; if (row < cols[col].minRow) cols[col].minRow = row; }
    }
    if (Object.keys(cols).length === 0) return false;
    ws.dataValidations.model = {};
    for (const col of Object.keys(cols)) {
      const info = cols[col];
      const start = info.minRow || 2;
      const end = Math.max(info.maxRow, lastRow || 0);
      ws.dataValidations.add(`${col}${start}:${col}${end}`, {
        type: info.v.type || 'list',
        allowBlank: info.v.allowBlank !== false,
        showErrorMessage: info.v.showErrorMessage !== false,
        formulae: info.v.formulae,
      });
    }
    return true;
  } catch (e) { return false; }
}
// === FIN FIX DROPDOWNS ===

// === VERDE CONCILIADO 2026-06-02: las filas con col E = "Si" se pintan de verde (FFB7E1CD,
// el MISMO verde que ya trae el archivo en su paleta). Se hace con una regla de formato
// condicional tipo 'expression' (exceljs la serializa bien; containsText la rompe). Match
// EXACTO a "Si" (no pinta "Comisiones"/"Ecuabet"/etc). Idempotente. ===
function _aplicarVerdeConciliado(ws, lastRow) {
  try {
    const VERDE = 'FFB7E1CD';
    const keep = (ws.conditionalFormattings || []).map(cf => {
      cf.rules = (cf.rules || []).filter(r => !(r.type === 'expression' && (r.formulae || []).some(f => String(f).replace(/\s/g, '').includes('="Si"'))));
      return cf;
    }).filter(cf => (cf.rules || []).length > 0);
    ws.conditionalFormattings = keep;
    ws.addConditionalFormatting({
      ref: `D2:E${lastRow}`,
      rules: [{ type: 'expression', priority: 1, formulae: ['$E2="Si"'],
        style: { fill: { type: 'pattern', pattern: 'solid', bgColor: { argb: VERDE }, fgColor: { argb: VERDE } } } }],
    });
    return true;
  } catch (e) { return false; }
}
// === FIN VERDE ===

// Write Yopago final: carga paso1 + escribe col D (Banco) y col E (Confirmado) de las conciliadas.
