await wb.xlsx.load(buf);

const data = item.json;
const filas = data.filas || [];
const headers = data.headers || [];
if (filas.length === 0) throw new Error('No hay filas para escribir paso3');

const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const ahora = new Date();
const sheetName = meses[ahora.getMonth()] + ' ' + ahora.getFullYear();
const monthRegex = /^(Enero|Febrero|Marzo|Abril|Mayo|Junio|Julio|Agosto|Septiembre|Octubre|Noviembre|Diciembre)\s+\d{4}$/i;
function pickSheet(wb, preferred) {
  let ws = wb.getWorksheet(preferred);
  if (ws) return ws;
  const monthSheets = wb.worksheets.filter(w => monthRegex.test(w.name));
  if (monthSheets.length > 0) return monthSheets[monthSheets.length - 1];
  const visible = wb.worksheets.filter(w => !w.name.startsWith('_'));
  if (visible.length > 0) return visible[visible.length - 1];
  return wb.worksheets[wb.worksheets.length - 1];
}
const ws = pickSheet(wb, sheetName);

// Detectar columnas Confirmado (E) y Banco (D) por header
function colByHeader(pred, fallback) {
  for (let i = 0; i < headers.length; i++) { if (pred(String(headers[i]).toLowerCase())) return i + 1; }
  return fallback;
}
const colConfirmado = colByHeader(h => h === 'confirmado' || h.includes('confirma'), 5);
const colBanco = colByHeader(h => h === 'banco' || h.includes('banco'), 4);

let updatedConf = 0, updatedBanco = 0;
for (const fila of filas) {
  const rowNum = fila.__rowNum__;
  if (!rowNum) continue;
  const conf = fila.Confirmado || fila.confirmado || '';
  if (!conf) continue;
  const row = ws.getRow(rowNum);
  // col E (Confirmado): solo si esta vacia (preserva cambios manuales)
  const exE = row.getCell(colConfirmado).value;
  if (exE == null || String(exE).trim() === '') { row.getCell(colConfirmado).value = conf; updatedConf++; }
  // col D (Banco): FIX 2026-06-02 - escribir el banco identificado en la conciliacion, si esta vacia
  const banco = fila.Banco || fila.banco || '';
  if (banco) {
    const exD = row.getCell(colBanco).value;
    if (exD == null || String(exD).trim() === '') { row.getCell(colBanco).value = banco; updatedBanco++; }
  }
  row.commit();
}

// FIX DROPDOWNS 2026-06-02: re-emitir listas desplegables limpias (paso1 ya las trae limpias).
const _dvOk = _fixDropdowns(ws, ws.rowCount);
// VERDE CONCILIADO 2026-06-02: pintar verde las filas con E="Si".
const _verdeOk = _aplicarVerdeConciliado(ws, ws.rowCount);

const out = await wb.xlsx.writeBuffer();
const b64 = Buffer.from(out).toString('base64');

return [{
  json: { ok: true, rowCount: filas.length, updatedConf, updatedBanco, sheetName: ws.name, pestanas: wb.worksheets.length, colConfirmado, colBanco, dropdowns_restauradas: _dvOk, verde_aplicado: _verdeOk, fallbackUsed: ws.name !== sheetName },
  binary: {
    data: {
      data: b64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: 'paso3_Recargas Concesionario Yopago.xlsx',
      fileExtension: 'xlsx',
    }
  }
}];

// Prep amarillo: arma 1 item por banco con movimientos conciliados (a marcar en paso2)
const conc = $('Cruzar y conciliar').first().json;
const amarillo = conc._amarillo || [];
const bancos = ($('Separar paso1 y paso2').first().json.bancos) || [];
function nb(n){ n=String(n).toLowerCase(); if(n.includes('valles')||n.includes('lirio'))return 'Valles de lirio'; if(n.includes('credil'))return 'Coop Credil'; if(n.includes('pichincha'))return 'Pichincha'; return ''; }
const byBanco={};
for(const m of amarillo){ (byBanco[m.banco]=byBanco[m.banco]||[]).push(m); }
const out=[];
for(const b of bancos){ const lab=nb(b.name); const movs=byBanco[lab]||[]; if(movs.length>0) out.push({json:{ id:b.id, name:b.name, banco:lab, movs }}); }
return out;

// Marcar amarillo paso2 (2026-06-02): para cada banco con movimientos conciliados, pinta
// en AMARILLO (FFFFFF00) la celda del 'valor' del movimiento de origen, identificado por
// doc + fecha + valor (clave unica; el numero de documento solo NO es unico). Preserva los
// amarillos historicos y NO pinta de mas. Modo: Run Once for All Items.
const ExcelJS = require('exceljs');
const AM = 'FFFFFF00';

function _num(v){ const n = parseFloat(String(v == null ? '' : v).replace(/[^0-9.\-]/g, '')); return isNaN(n) ? null : Math.round(n * 100) / 100; }
function _fch(v){ return String(v == null ? '' : v).trim().replace(/\//g, '-'); }
function _h(s){ return String(s || '').trim().toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, ''); }

const items = $input.all();
const prep = $('Prep amarillo').all(); // tras el Download, los movs/id vienen de Prep (mismo orden 1:1)
const out = [];
for (let i = 0; i < items.length; i++) {
  const info = (prep[i] && prep[i].json) || items[i].json || {};
  const movs = info.movs || [];
  const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
  const wb = new ExcelJS.Workbook();
  await wb.xlsx.load(buf);
  const ws = wb.worksheets[0];

  // detectar columnas por encabezado (fila 1)
  let colDoc = 0, colFecha = 0, colValor = 0;
  const maxC = ws.columnCount || 26;
  for (let c = 1; c <= maxC; c++) {
    const h = _h(ws.getRow(1).getCell(c).value);
    if (!colDoc && (h === 'documento' || h === 'doc')) colDoc = c;
    if (!colFecha && h === 'fecha') colFecha = c;
    if (!colValor && (h === 'valor' || h === 'monto')) colValor = c;
  }
  if (!colValor) colValor = colDoc ? colDoc + 1 : 7;
  if (!colDoc) colDoc = 2;
  if (!colFecha) colFecha = 1;

  const keys = new Set(movs.map(m => `${String(m.doc).trim()}|${_fch(m.fecha)}|${_num(m.valor)}`));
  let marcadas = 0;
  const total = ws.rowCount;
  for (let r = 2; r <= total; r++) {
    const row = ws.getRow(r);
    const k = `${String(row.getCell(colDoc).value || '').trim()}|${_fch(row.getCell(colFecha).value)}|${_num(row.getCell(colValor).value)}`;
    if (keys.has(k)) {
      row.getCell(colValor).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: AM }, bgColor: { argb: AM } };
      marcadas++;
    }
  }

  const b64 = Buffer.from(await wb.xlsx.writeBuffer()).toString('base64');
  out.push({
    json: { fileId: info.id, name: info.name, banco: info.banco, movimientos: movs.length, marcadas },
    binary: { data: { data: b64, mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', fileName: info.name || 'paso2.xlsx', fileExtension: 'xlsx' } },
  });
}
return out;
